  ('social-worker-moex-00111', 'social-worker', 'social-worker-moex-114-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體工作者處理非自願或抗拒的成員之作法，下列何者錯誤？', '["鼓勵抗拒的成員使用「我」語言陳述與表達，對自己的行為、感覺和想法負責", "儘量使用面質技術，以降低抗拒", "初期避免談論抽象的結果，而將焦點放在成員沒有真正去面對的問題", "協助成員設定期望目標，增加他們選擇的機會"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:01+00:00", "source_pdf_sha1": "f49f57383162", "answer_pdf_sha1": "2baead120889", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
