  ('social-worker-moex-00113', 'social-worker', 'social-worker-moex-114-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在評鑑過程，評鑑委員若需調閱團體工作紀錄，應如何處理以符合倫理原則？①評鑑屬於保密原', '["提供去除可辨識個人身分資訊的團體工作紀 錄", "評鑑委員必須簽署保密同意書，並僅能在機構內閱讀團體工作紀錄", "經團體工作者同意 後，可調閱團體工作紀錄", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:01+00:00", "source_pdf_sha1": "f49f57383162", "answer_pdf_sha1": "2baead120889", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
