  ('social-worker-moex-00115', 'social-worker', 'social-worker-moex-114-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「永續城市與社區」是聯合國永續發展目標（SDGs）之一，下列何者並非社區工作者達成此目標 的作法？', '["激發社區居民改變的意願，從生活中實踐低碳交通", "鼓勵社區參與，邀請居民共同發想永續發展的對策", "運用社區問題解決的過程，培養社區居民自治能力", "落實決策者角色，敦促居民加速改善社區環境品質"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:01+00:00", "source_pdf_sha1": "f49f57383162", "answer_pdf_sha1": "2baead120889", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
